        rio_re[m*ms+2*ios] = x2_re; rio_im[m*ms+2*ios] = x2_im;
        rio_re[m*ms+3*ios] = x3_re; rio_im[m*ms+3*ios] = x3_im;
        rio_re[m*ms+4*ios] = x4_re; rio_im[m*ms+4*ios] = x4_im;
